96	func (s *NezhaHandler) ReportSystemState(stream pb.NezhaService_ReportSystemStateServer) error {
97		clientID, err := s.Auth.Check(stream.Context())
98		if err != nil {
99			return err
100		}
101		var state *pb.State
102		for {
103			state, err = stream.Recv()
104			if err != nil {
105				log.Printf("NEZHA>> ReportSystemState error: %v, clientID: %d\n", err, clientID)
106				return err
107			}
108			innerState := model.PB2State(state)
109	
110			server, ok := singleton.ServerShared.Get(clientID)
111			if !ok || server == nil {
112				return errors.New("server not found")
113			}
114	
115			server.LastActive = time.Now()
116			server.State = &innerState
117	
118			if singleton.TSDBEnabled() {
119				maxTemp := 0.0
120				for _, t := range innerState.Temperatures {
121					if t.Temperature > maxTemp {
122						maxTemp = t.Temperature
123					}
124				}
125				maxGPU := 0.0
126				for _, g := range innerState.GPU {
127					if g > maxGPU {
128						maxGPU = g
129					}
130				}
131				if err := singleton.TSDBShared.WriteServerMetrics(&tsdb.ServerMetrics{
132					ServerID:       clientID,
133					Timestamp:      time.Now(),
134					CPU:            innerState.CPU,
135					MemUsed:        innerState.MemUsed,
136					SwapUsed:       innerState.SwapUsed,
137					DiskUsed:       innerState.DiskUsed,
138					NetInSpeed:     innerState.NetInSpeed,
139					NetOutSpeed:    innerState.NetOutSpeed,
140					NetInTransfer:  innerState.NetInTransfer,
141					NetOutTransfer: innerState.NetOutTransfer,
142					Load1:          innerState.Load1,
143					Load5:          innerState.Load5,
144					Load15:         innerState.Load15,
145					TCPConnCount:   innerState.TcpConnCount,
146					UDPConnCount:   innerState.UdpConnCount,
147					ProcessCount:   innerState.ProcessCount,
148					Temperature:    maxTemp,
149					Uptime:         innerState.Uptime,
150					GPU:            maxGPU,
151				}); err != nil {
152					log.Printf("NEZHA>> Failed to write server metrics to TSDB: %v", err)
153				}
154			}
155	
156			// 应对 dashboard / agent 重启的情况，如果从未记录过，先打点，等到小时时间点时入库
157			if server.PrevTransferInSnapshot == 0 || server.PrevTransferOutSnapshot == 0 {
158				server.PrevTransferInSnapshot = state.NetInTransfer
159				server.PrevTransferOutSnapshot = state.NetOutTransfer
160			}
161	
162			if err = stream.Send(&pb.Receipt{Proced: true}); err != nil {
163				return err
164			}
165		}
166	}
