211		if _, err := s.Auth.Check(stream.Context()); err != nil {
212			return err
213		}
214		id, err := stream.Recv()
215		if err != nil {
216			return err
217		}
218	
219		// ff05ff05 是 Nezha 的魔数，用于标识流 ID。校验由 isValidIOStreamMagic 完成，
220		// 历史 inline 检查曾因 && 短路放过几乎全部非魔数 payload (byte0==0xff 即通过)。
221		if id == nil || !isValidIOStreamMagic(id.Data) {
222			return fmt.Errorf("invalid stream id")
223		}
224	
225		go func() {
226			for {
227				if err := stream.Send(&pb.IOStreamData{Data: []byte{}}); err != nil {
228					log.Printf("NEZHA>> IOStream keepAlive error: %v\n", err)
229					return
230				}
231				time.Sleep(time.Second * 30)
232			}
233		}()
234	
235		streamId := string(id.Data[4:])
236	
237		if _, err := s.GetStream(streamId); err != nil {
238			return err
239		}
240		iw := grpcx.NewIOStreamWrapper(stream)
241		if err := s.AgentConnected(streamId, iw); err != nil {
242			return err
243		}
244		iw.Wait()
245		return nil
246	}
