248	func (s *NezhaHandler) ReportGeoIP(c context.Context, r *pb.GeoIP) (*pb.GeoIP, error) {
249		var clientID uint64
250		var err error
251		if clientID, err = s.Auth.Check(c); err != nil {
252			return nil, err
253		}
254	
255		geoip := model.PB2GeoIP(r)
256		use6 := r.GetUse6()
257	
258		if geoip.IP.IPv4Addr == "" && geoip.IP.IPv6Addr == "" {
259			ip, _ := c.Value(model.CtxKeyRealIP{}).(string)
260			if ip == "" {
261				ip, _ = c.Value(model.CtxKeyConnectingIP{}).(string)
262			}
263			geoip.IP.IPv4Addr = ip
264		}
265	
266		joinedIP := geoip.IP.Join()
267	
268		server, ok := singleton.ServerShared.Get(clientID)
269		if !ok || server == nil {
270			return nil, fmt.Errorf("server not found")
271		}
272	
273		// 检查并更新DDNS
274		if server.EnableDDNS && joinedIP != "" &&
275			(server.GeoIP == nil || server.GeoIP.IP != geoip.IP) {
276			ipv4 := geoip.IP.IPv4Addr
277			ipv6 := geoip.IP.IPv6Addr
278	
279			if err := singleton.ServerShared.UpdateDDNS(server, &model.IP{IPv4Addr: ipv4, IPv6Addr: ipv6}); err != nil {
280				log.Printf("NEZHA>> Failed to update DDNS for server %d: %v", err, server.ID)
281			}
282		}
283	
284		// 发送IP变动通知
285		if server.GeoIP != nil && singleton.Conf.EnableIPChangeNotification &&
286			((singleton.Conf.Cover == model.ConfigCoverAll && !singleton.Conf.IgnoredIPNotificationServerIDs[clientID]) ||
287				(singleton.Conf.Cover == model.ConfigCoverIgnoreAll && singleton.Conf.IgnoredIPNotificationServerIDs[clientID])) &&
288			server.GeoIP.IP.Join() != "" &&
289			joinedIP != "" &&
290			server.GeoIP.IP != geoip.IP {
291	
292			singleton.NotificationShared.SendNotification(singleton.Conf.IPChangeNotificationGroupID,
293				fmt.Sprintf(
294					"[%s] %s, %s => %s",
295					singleton.Localizer.T("IP Changed"),
296					server.Name, singleton.IPDesensitize(server.GeoIP.IP.Join()),
297					singleton.IPDesensitize(joinedIP),
298				),
299				"")
300		}
301	
302		// 根据内置数据库查询 IP 地理位置
303		var ip string
304		if geoip.IP.IPv6Addr != "" && (use6 || geoip.IP.IPv4Addr == "") {
305			ip = geoip.IP.IPv6Addr
306		} else {
307			ip = geoip.IP.IPv4Addr
308		}
309	
310		netIP := net.ParseIP(ip)
311		location, err := geoipx.Lookup(netIP)
312		if err != nil {
313			log.Printf("NEZHA>> geoip.Lookup: %v", err)
314		}
315		geoip.CountryCode = location
316	
317		// 将地区码写入到 Host
318		server.GeoIP = &geoip
319	
320		return &pb.GeoIP{Ip: nil, CountryCode: location, DashboardBootTime: singleton.DashboardBootTime}, nil
321	}
